from functools import lru_cache

class Solution:
    def validSequence(self, word1, word2):
        n, m = len(word1), len(word2)

        @lru_cache(maxsize=None)
        def can_match(i, j, used):
            if j == m:
                return True
            if n - i < m - j:
                return False
            if can_match(i + 1, j, used):
                return True
            if word1[i] == word2[j]:
                if can_match(i + 1, j + 1, used):
                    return True
            elif used == 0:
                if can_match(i + 1, j + 1, 1):
                    return True
            return False

        res = []
        i = j = 0
        used = 0
        while j < m and i < n:
            if n - i < m - j:
                break
            take_exact = word1[i] == word2[j]
            if take_exact and can_match(i + 1, j + 1, used):
                res.append(i)
                i += 1
                j += 1
            elif (not take_exact) and used == 0 and can_match(i + 1, j + 1, 1):
                res.append(i)
                i += 1
                j += 1
                used = 1
            else:
                i += 1
        can_match.cache_clear()
        if j < m:
            return []
        return res

