class Solution:
    def validSequence(self, word1, word2):
        n, m = len(word1), len(word2)
        j = m
        suf = [0] * (n + 1)
        for i in range(n - 1, -1, -1):
            if j > 0 and word1[i] == word2[j - 1]:
                j -= 1
            suf[i] = m - j
        res = []
        j = 0
        used = False
        for i in range(n):
            if j == m:
                break
            if word1[i] == word2[j]:
                res.append(i)
                j += 1
            elif not used:
                if m - (j + 1) <= suf[i + 1]:
                    used = True
                    res.append(i)
                    j += 1
        if j < m:
            return []
        return res

