var validSequence = function(word1, word2) {
    const n = word1.length, m = word2.length;
    const suf = new Array(n + 1).fill(0);
    let j = m;
    for (let i = n - 1; i >= 0; i--) {
        if (j > 0 && word1[i] === word2[j - 1]) j--;
        suf[i] = m - j;
    }
    const res = [];
    j = 0;
    let used = false;
    for (let i = 0; i < n; i++) {
        if (j === m) break;
        if (word1[i] === word2[j]) {
            res.push(i);
            j++;
        } else if (!used) {
            if (m - (j + 1) <= suf[i + 1]) {
                used = true;
                res.push(i);
                j++;
            }
        }
    }
    if (j < m) return [];
    return res;
};
